from collections import deque

class Queue:
    def __init__(self):
        self.items = deque()

    def enqueue(self, item):
        self.items.append(item)

    def dequeue(self):
        if self.items:
            return self.items.popleft()
        return 'Queue is empty'

    def peek(self):
        return self.items[0] if self.items else 'Queue is empty'

